105:     {
106:         Data::key_type key = ColumnsHashing::hash128(i, columns.size(), columns);
107:         typename Data::LookupResult it;
108:         bool inserted;
109:         partitions_map.emplace(key, it, inserted);
110: 
111:         if (inserted)
112:         {
113:             if (max_parts && partitions_count >= max_parts && throw_on_limit)
114:             {
115:                 ProfileEvents::increment(ProfileEvents::RejectedInserts);
116:                 throw Exception(ErrorCodes::TOO_MANY_PARTS,
117:                                 "Too many partitions for single INSERT block (more than {}). "
118:                                 "The limit is controlled by 'max_partitions_per_insert_block' setting. "
119:                                 "Large number of partitions is a common misconception. "
120:                                 "It will lead to severe negative performance impact, including slow server startup, "
121:                                 "slow INSERT queries and slow SELECT queries. Recommended total number of partitions "
122:                                 "for a table is under 1000..10000. Please note, that partitioning is not intended "
123:                                 "to speed up SELECT queries (ORDER BY key is sufficient to make range queries fast). "
124:                                 "Partitions are intended for data manipulation (DROP PARTITION, etc).", max_parts);
125:             }
