204: void addSubcolumnsFromSortingKeyAndSkipIndicesExpression(const ExpressionActionsPtr & expr, Block & block)
205: {
206:     /// Iterate over required columns in the expression and check if block doesn't have this column.
207:     /// It can happen only if required column is a actually a subcolumn of some column in the block.
208:     /// In this case we should add this subcolumn to the block as a separate column so it can be
209:     /// processed as a separate input in the expression actions.
210:     for (const auto & required_column : expr->getRequiredColumns())
211:     {
212:         if (!block.has(required_column))
213:             block.insert(block.getSubcolumnByName(required_column));
214:     }
