241: /// This method must be called after rename and commit of part
242: /// because a correct path is required for the keys of caches.
243: void MergeTreeDataWriter::TemporaryPart::prewarmCaches()
244: {
245:     size_t bytes_uncompressed = part->getBytesUncompressedOnDisk();
246: 
247:     if (auto mark_cache = part->storage.getMarkCacheToPrewarm(bytes_uncompressed))
248:     {
249:         for (const auto & stream : streams)
250:         {
251:             auto marks = stream.stream->releaseCachedMarks();
252:             addMarksToCache(*part, marks, mark_cache.get());
253:         }
254:     }
255: 
256:     if (auto index_cache = part->storage.getPrimaryIndexCacheToPrewarm(bytes_uncompressed))
257:     {
258:         /// Index was already set during writing. Now move it to cache.
259:         part->moveIndexToCache(*index_cache);
260:     }
