309: BlocksWithPartition MergeTreeDataWriter::splitBlockIntoParts(
310:     Block && block, size_t max_parts, const StorageMetadataPtr & metadata_snapshot, ContextPtr context, AsyncInsertInfoPtr async_insert_info)
311: {
312:     BlocksWithPartition result;
313:     if (!block || !block.rows())
314:         return result;
315: 
316:     metadata_snapshot->check(block, true);
317: 
318:     if (!metadata_snapshot->hasPartitionKey()) /// Table is not partitioned.
319:     {
320:         result.emplace_back(Block(block), Row{});
321:         if (async_insert_info != nullptr)
322:         {
323:             result[0].offsets = std::move(async_insert_info->offsets);
324:             result[0].tokens = std::move(async_insert_info->tokens);
325:         }
326:         return result;
327:     }
328: 
329:     Block block_copy = block;
330:     /// After expression execution partition key columns will be added to block_copy with names regarding partition function.
331:     auto partition_key_names_and_types = MergeTreePartition::executePartitionByExpression(metadata_snapshot, block_copy, context);
332: 
333:     ColumnRawPtrs partition_columns;
334:     partition_columns.reserve(partition_key_names_and_types.size());
335:     bool all_partition_columns_are_equal = true;
336:     for (const auto & element : partition_key_names_and_types)
337:     {
338:         partition_columns.emplace_back(block_copy.getByName(element.name).column.get());
339:         if (!partition_columns.back()->hasEqualValues())
340:             all_partition_columns_are_equal = false;
341:     }
342:     auto get_partition = [&](size_t row_num)
343:     {
344:         Row partition(partition_columns.size());
345:         for (size_t i = 0; i < partition_columns.size(); ++i)
346:             partition[i] = (*partition_columns[i])[row_num];
347:         return partition;
348:     };
349: 
350:     if (!all_partition_columns_are_equal)
351:     {
352:         PODArray<size_t> partition_num_to_first_row;
353:         IColumn::Selector selector;
354:         buildScatterSelector(partition_columns, partition_num_to_first_row, selector, max_parts, context);
355: 
356:         auto async_insert_info_with_partition = scatterAsyncInsertInfoBySelector(async_insert_info, selector, partition_num_to_first_row.size());
357: 
358:         size_t partitions_count = partition_num_to_first_row.size();
359:         result.reserve(partitions_count);
360: 
361:         for (size_t i = 0; i < partitions_count; ++i)
362:             result.emplace_back(block.cloneEmpty(), get_partition(partition_num_to_first_row[i]));
363: 
364:         for (size_t col = 0; col < block.columns(); ++col)
365:         {
366:             MutableColumns scattered = block.getByPosition(col).column->scatter(partitions_count, selector);
367:             for (size_t i = 0; i < partitions_count; ++i)
368:                 result[i].block.getByPosition(col).column = std::move(scattered[i]);
369:         }
370: 
371:         for (size_t i = 0; i < async_insert_info_with_partition.size(); ++i)
372:         {
373:             if (async_insert_info_with_partition[i] == nullptr)
374:             {
375:                 LOG_ERROR(
376:                     getLogger("MergeTreeDataWriter"),
377:                     "The {}th element in async_insert_info_with_partition is nullptr. There are totally {} partitions in the insert. Selector content is ({}). Offsets content is ({})",
378:                     i, partitions_count, fmt::join(selector.begin(), selector.end(), ","), fmt::join(async_insert_info->offsets.begin(), async_insert_info->offsets.end(), ","));
379:                 throw Exception(ErrorCodes::LOGICAL_ERROR, "Unexpected error for async deduplicated insert, please check error logs");
380:             }
381:             result[i].offsets = std::move(async_insert_info_with_partition[i]->offsets);
382:             result[i].tokens = std::move(async_insert_info_with_partition[i]->tokens);
383:         }
384:     }
385:     else
386:     {
387:         /// A typical case is when there is one partition (you do not need to split anything).
388:         /// NOTE: returning a copy of the original block so that calculated partition key columns
389:         /// do not interfere with possible calculated primary key columns of the same name.
390:         result.emplace_back(Block(block), get_partition(0));
391:         if (async_insert_info != nullptr)
392:         {
393:             result[0].offsets = std::move(async_insert_info->offsets);
394:             result[0].tokens = std::move(async_insert_info->tokens);
395:         }
396:     }
397: 
398:     return result;
399: }
