94: /// Do not start to merge parts, if free space is less than sum size of parts times specified coefficient.
95: /// This value is chosen to not allow big merges to eat all free space. Thus allowing small merges to proceed.
96: static const double DISK_USAGE_COEFFICIENT_TO_SELECT = 2;
97: 
98: /// To do merge, reserve amount of space equals to sum size of parts times specified coefficient.
99: /// Must be strictly less than DISK_USAGE_COEFFICIENT_TO_SELECT,
100: ///  because between selecting parts to merge and doing merge, amount of free space could have decreased.
101: static const double DISK_USAGE_COEFFICIENT_TO_RESERVE = 1.1;
