118: UInt64 MergeTreeDataMergerMutator::getMaxSourcePartsSizeForMerge(size_t max_count, size_t scheduled_tasks_count) const
119: {
120:     if (scheduled_tasks_count > max_count)
121:     {
122:         throw Exception(ErrorCodes::LOGICAL_ERROR,
123:             "Invalid argument passed to getMaxSourcePartsSize: scheduled_tasks_count = {} > max_count = {}",
124:             scheduled_tasks_count, max_count);
125:     }
126: 
127:     size_t free_entries = max_count - scheduled_tasks_count;
128:     const auto data_settings = data.getSettings();
129: 
130:     /// Always allow maximum size if one or less pool entries is busy.
131:     /// One entry is probably the entry where this function is executed.
132:     /// This will protect from bad settings.
133:     UInt64 max_size = 0;
134:     if (scheduled_tasks_count <= 1 || free_entries >= (*data_settings)[MergeTreeSetting::number_of_free_entries_in_pool_to_lower_max_size_of_merge])
135:         max_size = (*data_settings)[MergeTreeSetting::max_bytes_to_merge_at_max_space_in_pool];
136:     else
137:         max_size = static_cast<UInt64>(interpolateExponential(
138:             (*data_settings)[MergeTreeSetting::max_bytes_to_merge_at_min_space_in_pool],
139:             (*data_settings)[MergeTreeSetting::max_bytes_to_merge_at_max_space_in_pool],
140:             static_cast<double>(free_entries) / (*data_settings)[MergeTreeSetting::number_of_free_entries_in_pool_to_lower_max_size_of_merge]));
141: 
142:     return std::min(max_size, static_cast<UInt64>(data.getStoragePolicy()->getMaxUnreservedFreeSpace() / DISK_USAGE_COEFFICIENT_TO_SELECT));
143: }
