401: Block MergeTreeDataWriter::mergeBlock(
402:     Block && block,
403:     SortDescription sort_description,
404:     const Names & partition_key_columns,
405:     IColumn::Permutation *& permutation,
406:     const MergeTreeData::MergingParams & merging_params)
407: {
408:     OpenTelemetry::SpanHolder span("MergeTreeDataWriter::mergeBlock");
409: 
410:     size_t block_size = block.rows();
411: 
412:     span.addAttribute("clickhouse.rows", block_size);
413:     span.addAttribute("clickhouse.columns", block.columns());
414: 
415:     auto get_merging_algorithm = [&]() -> std::shared_ptr<IMergingAlgorithm>
416:     {
417:         switch (merging_params.mode)
418:         {
419:             /// There is nothing to merge in single block in ordinary MergeTree
420:             case MergeTreeData::MergingParams::Ordinary:
421:                 return nullptr;
422:             case MergeTreeData::MergingParams::Replacing:
423:                 return std::make_shared<ReplacingSortedAlgorithm>(
424:                     block, 1, sort_description, merging_params.is_deleted_column, merging_params.version_column, block_size + 1, /*block_size_bytes=*/0);
425:             case MergeTreeData::MergingParams::Collapsing:
426:                 return std::make_shared<CollapsingSortedAlgorithm>(
427:                     block, 1, sort_description, merging_params.sign_column,
428:                     false, block_size + 1, /*block_size_bytes=*/0, getLogger("MergeTreeDataWriter"));
429:             case MergeTreeData::MergingParams::Summing:
430:                 return std::make_shared<SummingSortedAlgorithm>(
431:                     block, 1, sort_description, merging_params.columns_to_sum,
432:                     partition_key_columns, block_size + 1, /*block_size_bytes=*/0);
433:             case MergeTreeData::MergingParams::Aggregating:
434:                 return std::make_shared<AggregatingSortedAlgorithm>(block, 1, sort_description, block_size + 1, /*block_size_bytes=*/0);
435:             case MergeTreeData::MergingParams::VersionedCollapsing:
436:                 return std::make_shared<VersionedCollapsingAlgorithm>(
437:                     block, 1, sort_description, merging_params.sign_column, block_size + 1, /*block_size_bytes=*/0);
438:             case MergeTreeData::MergingParams::Graphite:
439:                 return std::make_shared<GraphiteRollupSortedAlgorithm>(
440:                     block, 1, sort_description, block_size + 1, /*block_size_bytes=*/0, merging_params.graphite_params, time(nullptr));
441:         }
442:     };
443: 
444:     auto merging_algorithm = get_merging_algorithm();
445:     if (!merging_algorithm)
446:         return block;
447: 
448:     span.addAttribute("clickhouse.merging_algorithm", merging_algorithm->getName());
449: 
450:     Chunk chunk(block.getColumns(), block_size);
451: 
452:     IMergingAlgorithm::Input input;
453:     input.set(std::move(chunk));
454:     input.permutation = permutation;
455: 
456:     IMergingAlgorithm::Inputs inputs;
457:     inputs.push_back(std::move(input));
458:     merging_algorithm->initialize(std::move(inputs));
459: 
460:     IMergingAlgorithm::Status status = merging_algorithm->merge();
461: 
462:     /// Check that after first merge merging_algorithm is waiting for data from input 0.
463:     if (status.required_source != 0)
464:         throw Exception(ErrorCodes::LOGICAL_ERROR, "Required source after the first merge is not 0. Chunk rows: {}, is_finished: {}, required_source: {}, algorithm: {}", status.chunk.getNumRows(), status.is_finished, status.required_source, merging_algorithm->getName());
465: 
466:     status = merging_algorithm->merge();
467: 
468:     /// Check that merge is finished.
469:     if (!status.is_finished)
470:         throw Exception(ErrorCodes::LOGICAL_ERROR, "Merge is not finished after the second merge.");
471: 
472:     /// Merged Block is sorted and we don't need to use permutation anymore
473:     permutation = nullptr;
474: 
475:     return block.cloneWithColumns(status.chunk.getColumns());
476: }
