303: MergeTreeData::DataPartsVector MergeTreeDataMergerMutator::getDataPartsToSelectMergeFrom(const MergeTreeTransactionPtr & txn) const
304: {
305:     MergeTreeData::DataPartsVector res;
306:     if (!txn)
307:     {
308:         /// Simply get all active parts
309:         return data.getDataPartsVectorForInternalUsage();
310:     }
311: 
312:     /// Merge predicate (for simple MergeTree) allows to merge two parts only if both parts are visible for merge transaction.
313:     /// So at the first glance we could just get all active parts.
314:     /// Active parts include uncommitted parts, but it's ok and merge predicate handles it.
315:     /// However, it's possible that some transaction is trying to remove a part in the middle, for example, all_2_2_0.
316:     /// If parts all_1_1_0 and all_3_3_0 are active and visible for merge transaction, then we would try to merge them.
317:     /// But it's wrong, because all_2_2_0 may become active again if transaction will roll back.
318:     /// That's why we must include some outdated parts into `data_part`, more precisely, such parts that removal is not committed.
319:     MergeTreeData::DataPartsVector active_parts;
320:     MergeTreeData::DataPartsVector outdated_parts;
321: 
322:     {
323:         auto lock = data.lockParts();
324:         active_parts = data.getDataPartsVectorForInternalUsage({MergeTreeData::DataPartState::Active}, lock);
325:         outdated_parts = data.getDataPartsVectorForInternalUsage({MergeTreeData::DataPartState::Outdated}, lock);
326:     }
327: 
328:     ActiveDataPartSet active_parts_set{data.format_version};
329:     for (const auto & part : active_parts)
330:         active_parts_set.add(part->name);
331: 
332:     for (const auto & part : outdated_parts)
333:     {
334:         /// We don't need rolled back parts.
335:         /// NOTE When rolling back a transaction we set creation_csn to RolledBackCSN at first
336:         /// and then remove part from working set, so there's no race condition
337:         if (part->version.creation_csn == Tx::RolledBackCSN)
338:             continue;
339: 
340:         /// We don't need parts that are finally removed.
341:         /// NOTE There's a minor race condition: we may get UnknownCSN if a transaction has been just committed concurrently.
342:         /// But it's not a problem if we will add such part to `data_parts`.
343:         if (part->version.removal_csn != Tx::UnknownCSN)
344:             continue;
345: 
346:         active_parts_set.add(part->name);
347:     }
348: 
349:     /// Restore "active" parts set from selected active and outdated parts
350:     auto remove_pred = [&](const MergeTreeData::DataPartPtr & part) -> bool
351:     {
352:         return active_parts_set.getContainingPart(part->info) != part->name;
353:     };
354: 
355:     std::erase_if(active_parts, remove_pred);
356: 
357:     std::erase_if(outdated_parts, remove_pred);
358: 
359:     MergeTreeData::DataPartsVector data_parts;
360:     std::merge(
361:         active_parts.begin(),
362:         active_parts.end(),
363:         outdated_parts.begin(),
364:         outdated_parts.end(),
365:         std::back_inserter(data_parts),
366:         MergeTreeData::LessDataPart());
367: 
368:     return data_parts;
369: }
