46: static void filterColumns(Columns & columns, const IColumn::Filter & filter, size_t filter_bytes)
47: {
48:     for (auto & column : columns)
49:     {
50:         if (column)
51:         {
52:             if (column->size() != filter.size())
53:                 throw Exception(ErrorCodes::LOGICAL_ERROR, "Size of column {} doesn't match size of filter {}",
54:                     column->size(), filter.size());
55: 
56:             column = column->filter(filter, filter_bytes);
57: 
58:             if (column->empty())
59:             {
60:                 columns.clear();
61:                 return;
62:             }
63:         }
64:     }
65: }
